const VARIANTS = { dawn, day, dusk, night };

function pick(hour) {
  if (hour >= 5  && hour < 8)  return "dawn";
  if (hour >= 8  && hour < 17) return "day";
  if (hour >= 17 && hour < 20) return "dusk";
  return "night";
}

export default function handler(req, res) {
  const tz = (req.query && req.query.tz) || TZ;
  let hour = 12;
  try {
    hour = parseInt(
      new Intl.DateTimeFormat("en-US", { timeZone: tz, hour: "2-digit", hourCycle: "h23" })
        .format(new Date()), 10
    );
  } catch (e) {}
  const svg = VARIANTS[pick(hour)] || dusk;
  res.setHeader("Content-Type", "image/svg+xml; charset=utf-8");
  // short cache so the sky changes through the day (GitHub proxies images, so it
  // won't be instant, but it will roll over within minutes of each phase)
  res.setHeader("Cache-Control", "public, max-age=0, s-maxage=300, stale-while-revalidate=300");
  res.status(200).send(svg);
}
